const checks = [];
const today = new Date().toISOString().split('T')[0];
const hour = new Date().getUTCHours().toString().padStart(2, '0');
return [{ json: { checks, today, hour, logKey: `99_System/logs/health-monitor-${today}-${hour}.json` } }];

const init = $('Init Checks').first().json;
const nsCheck = $('S3: Check North Star').first().json;
const mtlCheck = $('S3: Check MTL').first().json;
const nowIso = new Date().toISOString();

function toCheck(name, label, raw, suggestion) {
  const failed = !!raw.error;
  return {
    name,
    label,
    status: failed ? 'fail' : 'pass',
    detail: failed ? String(raw.error).slice(0, 200) : 'reachable',
    last_checked: nowIso,
    suggestion: failed ? suggestion : ''
  };
}
const checks = [
  toCheck('minio_north_star', 'MinIO · North Star', nsCheck, 'Check MinIO at http://192.168.1.240:9000 — verify the obsidian-vault bucket and the 000_Master Dashboard/North Star.md key.'),
  toCheck('minio_mtl', 'MinIO · Master Task List', mtlCheck, 'Check the MTL key path. If MinIO is up but this fails, the key was renamed or the bucket policy changed.')
];
const anyFail = checks.some(c => c.status === 'fail');
const passCount = checks.filter(c => c.status === 'pass').length;

// Pretty subject + html for the alert email
function badge(status) {
  const color = status === 'pass' ? '#16a34a' : '#dc2626';
  const glyph = status === 'pass' ? '✓' : '✗';
  return `<span style="display:inline-block;background:${color};color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:700">${glyph} ${status.toUpperCase()}</span>`;
}
let rows = '';
for (const c of checks) {
  rows += `<tr style="border-bottom:1px solid #e5e7eb">
    <td style="padding:10px 12px;font-size:13px"><strong>${c.label}</strong><div style="font-size:11px;color:#6b7280;margin-top:2px">${c.detail}</div></td>
    <td style="padding:10px 12px;text-align:right;white-space:nowrap">${badge(c.status)}</td>
  </tr>`;
  if (c.status === 'fail' && c.suggestion) {
    rows += `<tr style="background:#fef2f2;border-bottom:1px solid #fecaca"><td colspan="2" style="padding:8px 12px;font-size:11px;color:#991b1b"><strong>Action:</strong> ${c.suggestion}</td></tr>`;
  }
}
const html = `<!DOCTYPE html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;background:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#1a1a1a;line-height:1.5">
<div style="max-width:600px;margin:0 auto;background:#ffffff">
<noscript style="display:block;padding:8px 16px;background:#fef2f2;color:#991b1b;font-size:12px">Health check FAILED · ${passCount}/${checks.length} services up · ${init.today}</noscript>
<div style="background:${anyFail ? '#dc2626' : '#16a34a'};color:white;padding:20px">
  <h1 style="margin:0;font-size:18px;font-weight:700">${anyFail ? '🚨' : '✅'} Infrastructure Health</h1>
  <p style="margin:6px 0 0;font-size:13px;opacity:0.9">${passCount}/${checks.length} services up · ${init.today}</p>
</div>
<div style="padding:0">
  <table style="width:100%;border-collapse:collapse"><tbody>${rows}</tbody></table>
</div>
<div style="padding:14px 20px;background:#f9fafb;font-size:11px;color:#6b7280">Checked at ${nowIso} · Logs: <code>99_System/logs/health-monitor-*</code></div>
<div style="background:#1a1a1a;color:#9ca3af;padding:10px 20px;text-align:center;font-size:11px">Life OS Health Monitor</div>
</div></body></html>`;
const subject = anyFail ? `🚨 Health Check FAILED — ${passCount}/${checks.length} up — ${init.today}` : `✓ Health OK — ${passCount}/${checks.length} up — ${init.today}`;

const log = JSON.stringify({
  workflow: 'system-health-monitor',
  run_date: init.today,
  finished_at: nowIso,
  status: anyFail ? 'fail' : 'pass',
  checks
}, null, 2);

return [{ json: { checks, anyFail, html, subject, logKey: init.logKey, logContent: log, today: init.today } }];

const content = $json.logContent;
const key = $json.logKey;
const buf = Buffer.from(content, 'utf-8');
return [{ json: $json, binary: { data: { data: buf.toString('base64'), mimeType: 'application/json', fileName: key.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];
